import { requireAuth } from '@/lib/supabase/server';
import { createClient } from '@/lib/supabase/server';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { BarChart2, TrendingUp, Users, DollarSign, Calendar, Activity } from 'lucide-react';

export default async function AdminMetricsPage() {
    const profile = await requireAuth();
    const supabase = await createClient();

    // Fetch various metrics
    const [usersRes, appointmentsRes, transactionsRes, dealsRes] = await Promise.all([
        supabase.from('profiles').select('id, created_at'),
        supabase.from('medical_appointments').select('id, status, created_at'),
        supabase.from('financial_transactions').select('amount, type, created_at'),
        supabase.from('crm_deals').select('id, stage, value, created_at'),
    ]);

    const users = usersRes.data || [];
    const appointments = appointmentsRes.data || [];
    const transactions = transactionsRes.data || [];
    const deals = dealsRes.data || [];

    // Calculate metrics
    const thisMonth = new Date();
    thisMonth.setDate(1);

    const newUsersThisMonth = users.filter((u: any) =>
        new Date(u.created_at) >= thisMonth
    ).length;

    const appointmentsThisMonth = appointments.filter((a: any) =>
        new Date(a.created_at) >= thisMonth
    ).length;

    const completedAppointments = appointments.filter((a: any) =>
        a.status === 'completed'
    ).length;

    const totalRevenue = transactions
        .filter((t: any) => t.type === 'income' || t.type === 'entrada')
        .reduce((sum: number, t: any) => sum + (t.amount || 0), 0);

    const totalDealsValue = deals.reduce((sum: number, d: any) =>
        sum + (typeof d.value === 'number' ? d.value : 0), 0
    );

    const wonDeals = deals.filter((d: any) => d.stage === 'fechado_ganho').length;

    return (
        <div className="space-y-6">
            <div>
                <h1 className="text-2xl font-bold">Métricas da Plataforma</h1>
                <p className="text-muted-foreground">Visão geral de performance do sistema</p>
            </div>

            {/* Stats Grid */}
            <div className="grid gap-4 md:grid-cols-3 lg:grid-cols-4">
                <Card>
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-sm font-medium">Novos Usuários (Mês)</CardTitle>
                        <Users className="h-4 w-4 text-blue-500" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold">{newUsersThisMonth}</div>
                        <p className="text-xs text-muted-foreground">de {users.length} total</p>
                    </CardContent>
                </Card>

                <Card>
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-sm font-medium">Consultas (Mês)</CardTitle>
                        <Calendar className="h-4 w-4 text-purple-500" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold">{appointmentsThisMonth}</div>
                        <p className="text-xs text-muted-foreground">{completedAppointments} concluídas</p>
                    </CardContent>
                </Card>

                <Card>
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-sm font-medium">Receita Total</CardTitle>
                        <DollarSign className="h-4 w-4 text-green-500" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold">
                            {new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(totalRevenue)}
                        </div>
                    </CardContent>
                </Card>

                <Card>
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-sm font-medium">Valor Pipeline</CardTitle>
                        <TrendingUp className="h-4 w-4 text-orange-500" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold">
                            {new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(totalDealsValue)}
                        </div>
                        <p className="text-xs text-muted-foreground">{wonDeals} deals ganhos</p>
                    </CardContent>
                </Card>
            </div>

            {/* Performance Cards */}
            <div className="grid gap-6 md:grid-cols-2">
                <Card>
                    <CardHeader>
                        <CardTitle className="flex items-center gap-2">
                            <BarChart2 className="h-5 w-5" />
                            Resumo de Performance
                        </CardTitle>
                    </CardHeader>
                    <CardContent className="space-y-4">
                        <div className="flex justify-between items-center">
                            <span className="text-muted-foreground">Total de Usuários</span>
                            <span className="font-bold">{users.length}</span>
                        </div>
                        <div className="flex justify-between items-center">
                            <span className="text-muted-foreground">Total de Consultas</span>
                            <span className="font-bold">{appointments.length}</span>
                        </div>
                        <div className="flex justify-between items-center">
                            <span className="text-muted-foreground">Total de Deals</span>
                            <span className="font-bold">{deals.length}</span>
                        </div>
                        <div className="flex justify-between items-center">
                            <span className="text-muted-foreground">Total de Transações</span>
                            <span className="font-bold">{transactions.length}</span>
                        </div>
                    </CardContent>
                </Card>

                <Card>
                    <CardHeader>
                        <CardTitle className="flex items-center gap-2">
                            <Activity className="h-5 w-5" />
                            Status do Sistema
                        </CardTitle>
                    </CardHeader>
                    <CardContent className="space-y-4">
                        <div className="flex justify-between items-center">
                            <span className="text-muted-foreground">API Status</span>
                            <span className="font-bold text-green-500">Online</span>
                        </div>
                        <div className="flex justify-between items-center">
                            <span className="text-muted-foreground">Database</span>
                            <span className="font-bold text-green-500">Conectado</span>
                        </div>
                        <div className="flex justify-between items-center">
                            <span className="text-muted-foreground">Edge Functions</span>
                            <span className="font-bold text-green-500">Ativas</span>
                        </div>
                    </CardContent>
                </Card>
            </div>
        </div>
    );
}
